#include <iostream>
#include <string>
#include <vector>
#include <cstring>
#include <cctype>

// The countVowels function, identical to the one in 4797.cpp for testing.
int countVowels(const char* str) {
    if (str == nullptr) {
        return 0;
    }

    int count = 0;
    for (int i = 0; str[i] != '\0'; ++i) {
        char c = std::tolower(static_cast<unsigned char>(str[i]));
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            count++;
        }
    }
    return count;
}

int main() {
    std::vector<std::pair<const char*, int>> tests = {
        {"Hello World!", 3},
        {"Programming is FUN", 5},
        {"AEIOUaeiou", 10},
        {"Rhythm", 0},
        {"", 0}
    };

    for (const auto& test : tests) {
        char buffer[256]; 
        if (test.first != nullptr) {
            strcpy(buffer, test.first);
        } else {
            buffer[0] = '\0'; 
        }

        int result = countVowels(buffer);
        std::cout << "Number of vowels: " << result << std::endl;
    }
    return 0;
}
